async (params, browser) => {
  // Open competition page
  await browser.open(`https://www.kaggle.com/competitions/${params.competition_slug}`)

  // Wait for competition page
  await browser.waitForSelector('h1, [role=\'main\']', 15000)

  // Let page render
  await browser.wait(3000)

  // Scroll for more content
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract competition data
  const page_data = await browser.evaluate(`const title = document.querySelector('h1')?.textContent?.trim() || document.title.split('|')[0]?.trim() || ''; const paragraphs = Array.from(document.querySelectorAll('p, [class*="description"], [class*="markdown"]')).map(e => e.textContent.trim()).filter(t => t.length > 50); const desc = paragraphs.slice(0, 3).join(' ').substring(0, 1500); const allText = document.body.innerText; const prizeMatch = allText.match(/\$[\d,]+/); const teamMatch = allText.match(/(\d[\d,]*)\s*teams?/i); const deadlineMatch = allText.match(/(?:deadline|closes?|ends?)\s*:?\s*([A-Za-z]+\s+\d{1,2},?\s+\d{4})/i); const timeEl = document.querySelector('time'); const tags = []; const seen = new Set(); document.querySelectorAll('a[href*="/tags/"], a[href*="/competitions?"]').forEach(a => { const text = a.textContent.trim(); if (text && text.length < 50 && !seen.has(text)) { seen.add(text); tags.push(text); } }); return { title, description: desc, prize: prizeMatch ? prizeMatch[0] : '', teams: teamMatch ? teamMatch[1] : '', deadline: deadlineMatch ? deadlineMatch[1] : (timeEl ? timeEl.textContent.trim() : ''), tags: tags.slice(0, 10), url: window.location.href };`)

  return page_data
}
